SELECT pr.* FROM production_records pr


        AND pr.qr_code_id = #{qrCodeId}


        AND pr.stage_id = #{stageId}


        AND pr.operator_id = #{operatorId}


        AND pr.order_item_id IN (
            SELECT id FROM order_items WHERE order_id = #{orderId}
        )


        AND pr.scan_time >= #{startDate}


        AND pr.scan_time <= #{endDate}


ORDER BY pr.created_at DESC
LIMIT #{offset}, #{size}

